// Boucle for classique
for (let i = 0; i < 5; i++) {
  console.log('Tour numéro ' + i);
}

// Parcourir un tableau avec for...of
const prenoms = ['Alice', 'Bob', 'Carla'];
for (const prenom of prenoms) {
  console.log('Bonjour ' + prenom);
}

// Boucle while
let compteur = 0;
while (compteur < 3) {
  console.log(compteur);
  compteur++; // ne pas oublier sinon boucle infinie !
}
